files.content:
.onmark-film,
.onmark-scene,
.onmark-shot {
  width: 100%;
  height: 100%;
}

.onmark-shot {
  position: relative;
  overflow: hidden;
  background: #080a0d;
}

.onmark-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  filter: brightness(0.48);
}

.onmark-title {
  position: absolute;
  left: 7vw;
  bottom: 8vh;
  margin: 0;
  color: #fff;
  font: 700 clamp(3rem, 8vw, 8rem)/0.95 sans-serif;
}

import { gsapMotion } from "onmark/motion/gsap";

export const motion = gsapMotion({
  title({ element, timeline }) {
    timeline.from(element, {
      opacity: 0,
      y: 36,
      duration: 0.45,
      ease: "power2.out",
    });
  },
});

.onmark-film,
.onmark-scene,
.onmark-shot {
  width: 100%;
  height: 100%;
}

.onmark-shot {
  position: relative;
  overflow: hidden;
}

#story {
  background: #5227ff;
}

#compile {
  background: #ff4f64;
}

#render {
  background: #00a67e;
}

.onmark-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  opacity: 0.76;
}

.onmark-title {
  position: absolute;
  left: 7vw;
  bottom: 8vh;
  margin: 0;
  color: white;
  font: 700 clamp(3rem, 9vw, 9rem)/1 sans-serif;
}

import { gsapMotion } from "onmark/motion/gsap";

export const motion = gsapMotion({
  shot({ element, timeline }) {
    timeline.from(element, {
      clipPath: "inset(0 100% 0 0)",
      duration: 0.55,
      ease: "power2.inOut",
    });
  },
});

.onmark-film,
.onmark-scene,
.onmark-shot {
  width: 100%;
  height: 100%;
}

.onmark-shot {
  position: relative;
  overflow: hidden;
  background: #111;
}

.onmark-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.onmark-title {
  position: absolute;
  left: 7vw;
  bottom: 20vh;
  margin: 0;
  color: white;
  font: 800 clamp(3rem, 9vw, 8rem)/1 sans-serif;
}

.onmark-call-to-action {
  position: absolute;
  left: 7vw;
  bottom: 9vh;
  padding: 0.8em 1.4em;
  border-radius: 999px;
  background: #e52b35;
  color: white;
  font: 700 clamp(1rem, 2.2vw, 2rem)/1 sans-serif;
}

import { gsapMotion } from "onmark/motion/gsap";

export const motion = gsapMotion({
  callToAction({ element, timeline }) {
    timeline.from(element, {
      opacity: 0,
      scale: 0.8,
      duration: 0.4,
      ease: "back.out(1.7)",
    });
  },
});

import { definePresentation } from "@onmark/authoring";
import type { PresentationContext } from "@onmark/runtime";

export const presentation = definePresentation(
  ({ document, media }: PresentationContext) => {
    const film = document.createElement("div");
    film.className = "onmark-film";

    const scene = document.createElement("div");
    scene.className = "onmark-scene";

    const shot = document.createElement("div");
    shot.className = "onmark-shot";

    const video = document.createElement("video");
    video.className = "onmark-video";
    video.src = media("media/native.mp4");

    const title = document.createElement("h1");
    title.className = "onmark-title";
    title.append("Write ");

    const accent = document.createElement("span");
    accent.className = "accent";
    accent.textContent = "native.";
    title.append(accent, " Render exact.");

    shot.append(video, title);
    scene.append(shot);
    film.append(scene);
    return film;
  },
);

.onmark-film,
.onmark-scene,
.onmark-shot {
  width: 100%;
  height: 100%;
}

.onmark-shot {
  position: relative;
  overflow: hidden;
  background: #090b0d;
}

.onmark-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  opacity: 0.55;
}

.onmark-title {
  position: absolute;
  left: 7vw;
  right: 7vw;
  bottom: 9vh;
  margin: 0;
  color: white;
  font: 700 clamp(2.5rem, 7vw, 7rem)/1.05 sans-serif;
}

.onmark-title .accent {
  color: #b8ff35;
}

import { gsapMotion } from "onmark/motion/gsap";

export const motion = gsapMotion({
  title({ element, timeline }) {
    timeline.from(element, {
      opacity: 0,
      y: 24,
      duration: 0.45,
      ease: "power2.out",
    });
  },
  selectors: {
    ".accent"({ element, timeline }) {
      timeline.from(element, {
        opacity: 0,
        scale: 0.72,
        duration: 0.35,
        ease: "back.out(1.8)",
      });
    },
  },
});

import { definePresentation } from "@onmark/authoring";
import type { PresentationContext } from "@onmark/runtime";

export const presentation = definePresentation(
  ({ document, media }: PresentationContext) => {
    const film = document.createElement("div");
    film.className = "onmark-film";

    const scene = document.createElement("div");
    scene.className = "onmark-scene";

    const shot = document.createElement("div");
    shot.className = "onmark-shot";

    const video = document.createElement("video");
    video.className = "onmark-video";
    video.src = media("media/grid.mp4");

    const grid = document.createElement("div");
    grid.className = "grid";
    grid.setAttribute("aria-hidden", "true");

    const title = document.createElement("h1");
    title.className = "onmark-title";
    title.textContent = "No tracks";

    shot.append(video, grid, title);
    scene.append(shot);
    film.append(scene);
    return film;
  },
);

.onmark-film,
.onmark-scene,
.onmark-shot {
  width: 100%;
  height: 100%;
}

.onmark-shot {
  position: relative;
  overflow: hidden;
  background: #080a10;
}

.onmark-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  opacity: 0.58;
}

.grid {
  position: absolute;
  inset: 0;
  background-image:
    linear-gradient(rgba(117, 255, 224, 0.22) 1px, transparent 1px),
    linear-gradient(90deg, rgba(117, 255, 224, 0.22) 1px, transparent 1px);
  background-size: 64px 64px;
  pointer-events: none;
}

.onmark-title {
  position: absolute;
  left: 7vw;
  bottom: 9vh;
  z-index: 1;
  margin: 0;
  color: white;
  font: 750 clamp(3rem, 9vw, 9rem)/1 sans-serif;
}

import { gsapMotion } from "onmark/motion/gsap";

export const motion = gsapMotion({
  selectors: {
    ".grid"({ element, timeline }) {
      timeline.from(element, {
        opacity: 0,
        duration: 0.7,
        ease: "power1.out",
      });
    },
  },
});
